    51→    async addDocument(buffer: Buffer, config: DocumentImportConfig): Promise<void> {
    52→        this.logger.log(`[DOCUMENT_PROCESSING_START] sourceId: ${config.sourceId}, docName: ${config.docName}, docType: ${config.docType}, bufferSize: ${buffer.length}`);
    53→
    54→        // Create document placeholder first
    55→        this.logger.log(`[DOCUMENT_DB_CREATE_START] sourceId: ${config.sourceId}`);
    56→        const docResult = await this.documentRepository.createDocument({
    57→            sourceId: config.sourceId,
    58→            name: config.docName
    59→        });
    60→
    61→        if (!docResult.success) {
    62→            this.logger.error(`[DOCUMENT_DB_CREATE_ERROR] sourceId: ${config.sourceId}, error: ${docResult.error}`);
    63→            return;
    64→        }
    65→
    66→        const docId = docResult.data.sourceId;
    67→        this.logger.log(`[DOCUMENT_DB_CREATE_SUCCESS] sourceId: ${config.sourceId}, docId: ${docId}`);
    68→
    69→        // Parse document to AST
    70→        this.logger.log(`[DOCUMENT_PARSING_START] sourceId: ${config.sourceId}, docType: ${config.docType}`);
    71→        let abstractDoc: ExtractedDocument;
    72→        const parseStartTime = Date.now();
    73→        switch (config.docType.toLowerCase()) {
    74→
    75→            case 'md':
    76→                abstractDoc = await this.markdownService.parse(buffer);
    77→                this.logger.log(`[DOCUMENT_PARSING_COMPLETE] sourceId: ${config.sourceId}, type: markdown, documentId: ${abstractDoc.id}, duration: ${Date.now() - parseStartTime}ms`);
    78→                break;
    79→
    80→            case 'pdf':
    81→            default:
    82→                abstractDoc = await this.pdfService.import(buffer, config.docName);
    83→                this.logger.log(`[DOCUMENT_PARSING_COMPLETE] sourceId: ${config.sourceId}, type: pdf, documentId: ${abstractDoc.id}, duration: ${Date.now() - parseStartTime}ms`);
    84→                break;
    85→        }
    86→
    87→        // Cleanup text
    88→        this.logger.log(`[TEXT_CLEANUP_START] sourceId: ${config.sourceId}, paragraphsBefore: ${abstractDoc.paragraphs.length}`);
    89→        
    90→        abstractDoc.paragraphs = abstractDoc.paragraphs.reduce((acc: Paragraph[], para) => {
    91→            const text = para.text
    92→                .trim()
    93→                .replace(/[\x00-\x08\x0B-\x0C\x0E-\x1F\x7F-\x9F]/g, '')
    94→                .normalize('NFKC')
    95→                .trim();
    96→
    97→            // Debug
    98→            // if (text.length !== para.text.length) {
    99→            //     console.warn(`Line cleanup [`, para.text, "] [", text, "]");
   100→            // }
   101→
   102→            if (text.length === 0) {
   103→                return acc;
   104→            }
   105→
   106→            para.text = text;
   107→            acc.push(para);
   108→            return acc;
   109→        }, []);
   110→
   111→        this.logger.log(`[TEXT_CLEANUP_COMPLETE] sourceId: ${config.sourceId}, paragraphsAfter: ${abstractDoc.paragraphs.length}`);
   112→
   113→        // Further analysis
   114→        this.logger.log(`[TEXT_ANALYSIS_START] sourceId: ${config.sourceId}`);
   115→        const analysisStartTime = Date.now();
   116→        await this.analysisService.addTextAnalysis(abstractDoc);
   117→        this.logger.log(`[TEXT_ANALYSIS_COMPLETE] sourceId: ${config.sourceId}, documentId: ${abstractDoc.id}, duration: ${Date.now() - analysisStartTime}ms`);
   118→
   119→        // Actually add text to document links/data
   120→        this.logger.log(`[TEXT_NODES_CREATE_START] sourceId: ${config.sourceId}, nodeCount: ${abstractDoc.paragraphs.length}`);
   121→        const textNodes: TextNodeData[] = abstractDoc.paragraphs.map(p => ({ nodePath: 'Unknown', ...p }));
   122→        const textNodesStartTime = Date.now();
   123→        await this.textService.createTextNodes(textNodes, { sourceId: docId });
   124→        this.logger.log(`[TEXT_NODES_CREATE_COMPLETE] sourceId: ${config.sourceId}, documentId: ${abstractDoc.id}, duration: ${Date.now() - textNodesStartTime}ms`);
   125→
   126→        const terminologies: string[] = [];
   127→        // Add to collections if they exist
   128→        if (config.collections && config.collections.length > 0) {
   129→            this.logger.log(`[COLLECTION_ASSOCIATION_START] sourceId: ${config.sourceId}, collections: ${config.collections.join(', ')}`);
   130→            for (let i = 0; i < config.collections.length; i++) {
   131→                this.logger.debug(`[COLLECTION_ASSOCIATION] sourceId: ${config.sourceId}, collection: ${config.collections[i]}`);
   132→                this.collectionService.associateDocument(config.collections[i], config.sourceId);
   133→
   134→                const terminology = await this.terminologyService.getTerminologyFromCollection(config.collections[i]);
   135→                console.log("Got terminology ID for collection ", terminology);
   136→                if (terminology) terminologies.push(terminology);
   137→            }
   138→            this.logger.log(`[COLLECTION_ASSOCIATION_COMPLETE] sourceId: ${config.sourceId}`);
   139→        }
   140→
   141→        // Now send request to the enrichment server
   142→        this.logger.log(`[ENRICHMENT_HANDOFF_START] sourceId: ${config.sourceId}`);
   143→        try {
   144→            console.log("Adding document with terminologies ", terminologies);
   145→            await this.enrichment.addDocument(config.sourceId, terminologies);
